import java.util.Scanner;
import java.lang.Math;

public class Main {
    static final int MAX_N = 36;
    static final int MAX_K = 12;
    static final double MAX_DIST = 1000000;

    public static double distance(int x1, int y1, int x2, int y2) {
        return Math.sqrt((x2 - x1) * (x2 - x1) + (y2 - y1) * (y2 - y1));
    }

    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int K = sc.nextInt();
            int[] x = new int[N];
            int[] y = new int[N];
            String[] s = new String[N];
            for (int i = 0; i < N; i++) {
                x[i] = sc.nextInt();
                y[i] = sc.nextInt();
            }
            for (int i = 0; i < N; i++) {
                s[i] = sc.next();
            }
            double min_dist = MAX_DIST;
            for (int mask = 1; mask < (1 << N); mask++) {
                int collected = 0;
                for (int i = 0; i < K; i++) {
                    for (int j = 0; j < N; j++) {
                        if ((mask & (1 << j)) != 0 && s[j].charAt(i) == '1') {
                            collected |= (1 << i);
                            break;
                        }
                    }
                }
                if (collected == (1 << K) - 1) {
                    double dist = 0;
                    int prev_x = 0, prev_y = 0;
                    for (int i = 0; i < N; i++) {
                        if ((mask & (1 << i)) != 0) {
                            dist += distance(prev_x, prev_y, x[i], y[i]);
                            prev_x = x[i];
                            prev_y = y[i];
                        }
                    }
                    dist += distance(prev_x, prev_y, 0, 0);
                    min_dist = Math.min(min_dist, dist);
                }
            }
            if (min_dist == MAX_DIST) {
                System.out.println(-1);
            } else {
                System.out.printf("%.6f\n", min_dist);
            }
        }
    }
}

